#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long factorial(int n) {
    long long result = 1;
    for (int i = 2; i <= n; i++) {
        result = (result * i) % MOD;
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        long long A[N + 1];
        for (int i = 0; i <= N; i++) {
            scanf("%lld", &A[i]);
        }
        long long result = 0;
        for (int i = 1; i <= N; i++) {
            result = (result + (A[i] * (A[i - 1] + A[i + 1])) % MOD * factorial(N - 1)) % MOD;
        }
        printf("%lld\n", result);
    }
    return 0;
}

