import java.util.Scanner;
public class Main {
    static final long MOD = 1000000007;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            long[] A = new long[N + 1];
            for (int i = 0; i <= N; i++) {
                A[i] = sc.nextLong();
            }
            long result = 0;
            for (int i = 1; i <= N; i++) {
                result = (result + (A[i] * (A[i - 1] + A[i + 1])) % MOD * factorial(N - 1)) % MOD;
            }
            System.out.println(result);
        }
    }
    public static long factorial(int n) {
        long result = 1;
        for (int i = 2; i <= n; i++) {
            result = (result * i) % MOD;
        }
        return result;
    }
}

