import sys
MOD = 1000000007

def factorial(n):
    result = 1
    for i in range(2, n + 1):
        result = (result * i) % MOD
    return result

def main():
    T = int(sys.stdin.readline().strip())
    for _ in range(T):
        N = int(sys.stdin.readline().strip())
        A = list(map(int, sys.stdin.readline().strip().split()))
        result = 0
        for i in range(1, N + 1):
            result = (result + (A[i] * (A[i - 1] + A[i + 1] if i < N else A[i - 1])) % MOD * factorial(N - 1)) % MOD
        print(result)
if __name__ == '__main__':
    main()

